#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_M 500005

// Define the structure for a graph edge
typedef struct Edge {
    int u, v;
} Edge;

// Define the structure for a graph
typedef struct Graph {
    int n, m;
    Edge* edges;
} Graph;

// Function to perform DFS traversal
void dfs(int node, int* visited, Graph* graph) {
    visited[node] = 1;
    for (int i = 0; i < graph->m; i++) {
        if (graph->edges[i].u == node && !visited[graph->edges[i].v]) {
            dfs(graph->edges[i].v, visited, graph);
        }
    }
}

// Function to calculate the number of unordered pairs
int calculate_pairs(Graph* graph) {
    int* visited = (int*) calloc(graph->n + 1, sizeof(int));
    int count = 0;
    for (int i = 1; i <= graph->n; i++) {
        if (!visited[i]) {
            dfs(i, visited, graph);
            count++;
        }
    }
    free(visited);
    return count * (count - 1) / 2;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    Graph graph;
    graph.n = n;
    graph.m = m;
    graph.edges = (Edge*) malloc(m * sizeof(Edge));
    for (int i = 0; i < m; i++) {
        scanf("%d %d", &graph.edges[i].u, &graph.edges[i].v);
    }
    printf("%d\n", calculate_pairs(&graph));
    free(graph.edges);
    return 0;
}

