    visited[node] = true;
    for (const auto& edge : graph.edges) {
        if (edge.u == node && !visited[edge.v]) {
            dfs(edge.v, visited, graph);
        }
    }
}

// Function to calculate the number of unordered pairs
int calculate_pairs(Graph& graph) {
    vector<bool> visited(graph.n + 1, false);
    int count = 0;
    for (int i = 1; i <= graph.n; i++) {
        if (!visited[i]) {
            dfs(i, visited, graph);
            count++;
        }
    }
    return count * (count - 1) / 2;
}

