import java.util.Scanner;
import java.util.Vector;

public class Main {
    // Define the structure for a graph edge
    static class Edge {
        int u, v;
        Edge(int u, int v) {
            this.u = u;
            this.v = v;
        }
    }

    // Define the structure for a graph
    static class Graph {
        int n, m;
        Vector<Edge> edges;
        Graph(int n, int m) {
            this.n = n;
            this.m = m;
            this.edges = new Vector<>();
        }
    }

    // Function to perform DFS traversal
    static void dfs(int node, boolean[] visited, Graph graph) {
        visited[node] = true;
        for (Edge edge : graph.edges) {
            if (edge.u == node && !visited[edge.v]) {
                dfs(edge.v, visited, graph);
            }
        }
    }

    // Function to calculate the number of unordered pairs
    static int calculate_pairs(Graph graph) {
        boolean[] visited = new boolean[graph.n + 1];
        int count = 0;
        for (int i = 1; i <= graph.n; i++) {
            if (!visited[i]) {
                dfs(i, visited, graph);
                count++;
            }
        }
        return count * (count - 1) / 2;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        Graph graph = new Graph(n, m);
        for (int i = 0; i < m; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            graph.edges.add(new Edge(u, v));
        }
        System.out.println(calculate_pairs(graph));
    }
}

