    visited[node] = True
    for edge in graph.edges:
        if edge.u == node and not visited[edge.v]:
            dfs(edge.v, visited, graph)

# Function to calculate the number of unordered pairs
def calculate_pairs(graph):
    visited = [False] * (graph.n + 1)
    count = 0
    for i in range(1, graph.n + 1):
        if not visited[i]:
            dfs(i, visited, graph)
            count += 1
    return count * (count - 1) // 2

